+package github.chains;
+
+import org.w3c.dom.Document;
+import org.w3c.dom.Element;
+import org.w3c.dom.Node;
+import org.w3c.dom.NodeList;
+import spoon.Launcher;
+import spoon.reflect.code.CtCodeSnippetStatement;
+import spoon.reflect.code.CtExpression;
+import spoon.reflect.code.CtInvocation;
+import spoon.reflect.code.CtStatement;
+import spoon.reflect.code.CtTypeAccess;
+import spoon.reflect.code.CtVariableRead;
+import spoon.reflect.declaration.CtElement;
+import spoon.reflect.declaration.CtLocalVariable;
+import spoon.reflect.factory.Factory;
+import spoon.reflect.reference.CtTypeReference;
+import spoon.reflect.visitor.filter.TypeFilter;
+
+import javax.xml.parsers.DocumentBuilderFactory;
+import javax.xml.transform.OutputKeys;
+import javax.xml.transform.TransformerFactory;
+import javax.xml.transform.dom.DOMSource;
+import javax.xml.transform.stream.StreamResult;
+import java.io.File;
+import java.nio.file.Files;
+import java.nio.file.Path;
+import java.util.HashSet;
+import java.util.List;
+import java.util.Set;
+
+public class Main {
+    private static final String LOGBACK_LOGGER = "ch.qos.logback.classic.Logger";
+    private static final String LOGBACK_LEVEL = "ch.qos.logback.classic.Level";
+    private static final String LOGBACK_APPENDER = "ch.qos.logback.core.Appender";
+    private static final String SLF4J_API = "org.slf4j:slf4j-api";
+    private static final String LOGBACK_CLASSIC = "ch.qos.logback:logback-classic";
+    private static final String TARGET_SLF4J_VERSION = "2.0.0";
+
+    public static void main(String[] args) throws Exception {
+        if (args.length != 1) {
+            throw new IllegalArgumentException("Usage: Main <project-root>");
+        }
+
+        Path projectRoot = Path.of(args[0]).toAbsolutePath().normalize();
+        updatePomIfNeeded(projectRoot.resolve("pom.xml"));
+        rewriteJavaSources(projectRoot);
+    }
+
+    private static void updatePomIfNeeded(Path pomPath) throws Exception {
+        if (!Files.isRegularFile(pomPath)) {
+            return;
+        }
+
+        Document document = DocumentBuilderFactory.newInstance().newDocumentBuilder().parse(pomPath.toFile());
+        document.getDocumentElement().normalize();
+
+        boolean hasLogbackClassic = false;
+        Element slf4jDependency = null;
+        Element slf4jVersion = null;
+
+        NodeList dependencies = document.getElementsByTagName("dependency");
+        for (int i = 0; i < dependencies.getLength(); i++) {
+            Node node = dependencies.item(i);
+            if (!(node instanceof Element dependency)) {
+                continue;
+            }
+
+            String groupId = childText(dependency, "groupId");
+            String artifactId = childText(dependency, "artifactId");
+            if (LOGBACK_CLASSIC.equals(groupId + ":" + artifactId)) {
+                String version = childText(dependency, "version");
+                if (version != null && version.startsWith("1.4")) {
+                    hasLogbackClassic = true;
+                }
+            }
+            if (SLF4J_API.equals(groupId + ":" + artifactId)) {
+                slf4jDependency = dependency;
+                Node versionNode = childNode(dependency, "version");
+                if (versionNode instanceof Element element) {
+                    slf4jVersion = element;
+                }
+            }
+        }
+
+        if (!hasLogbackClassic) {
+            return;
+        }
+
+        if (slf4jDependency == null) {
+            Element dependenciesElement = (Element) document.getElementsByTagName("dependencies").item(0);
+            if (dependenciesElement == null) {
+                return;
+            }
+            slf4jDependency = document.createElement("dependency");
+            appendChildElement(document, slf4jDependency, "groupId", "org.slf4j");
+            appendChildElement(document, slf4jDependency, "artifactId", "slf4j-api");
+            appendChildElement(document, slf4jDependency, "version", TARGET_SLF4J_VERSION);
+            dependenciesElement.appendChild(document.createTextNode("\n        "));
+            dependenciesElement.appendChild(slf4jDependency);
+            dependenciesElement.appendChild(document.createTextNode("\n    "));
+        } else {
+            if (slf4jVersion == null) {
+                appendChildElement(document, slf4jDependency, "version", TARGET_SLF4J_VERSION);
+            } else {
+                slf4jVersion.setTextContent(TARGET_SLF4J_VERSION);
+            }
+        }
+
+        TransformerFactory transformerFactory = TransformerFactory.newInstance();
+        var transformer = transformerFactory.newTransformer();
+        transformer.setOutputProperty(OutputKeys.INDENT, "yes");
+        transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "4");
+        transformer.transform(new DOMSource(document), new StreamResult(pomPath.toFile()));
+    }
+
+    private static void rewriteJavaSources(Path projectRoot) {
+        List<Path> sourceRoots = List.of(projectRoot.resolve("src/main/java"), projectRoot.resolve("src/test/java"));
+        Launcher launcher = new Launcher();
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+
+        for (Path sourceRoot : sourceRoots) {
+            if (Files.isDirectory(sourceRoot)) {
+                launcher.addInputResource(sourceRoot.toString());
+            }
+        }
+
+        launcher.buildModel();
+        Factory factory = launcher.getFactory();
+
+        Set<String> logbackLoggerVariables = new HashSet<>();
+        for (CtLocalVariable<?> localVariable : launcher.getModel().getElements(new TypeFilter<>(CtLocalVariable.class))) {
+            if (isLogbackLogger(localVariable.getType())) {
+                logbackLoggerVariables.add(localVariable.getSimpleName());
+                localVariable.setType(factory.Type().objectType());
+                if (localVariable.getDefaultExpression() != null && localVariable.getDefaultExpression().toString().contains("(" + LOGBACK_LOGGER + ")")) {
+                    CtExpression<?> initializer = localVariable.getDefaultExpression();
+                    if (initializer instanceof spoon.reflect.code.CtCastExpression<?> castExpression) {
+                        localVariable.setDefaultExpression((CtExpression) castExpression.getExpression());
+                    }
+                }
+            }
+        }
+
+        for (CtInvocation<?> invocation : launcher.getModel().getElements(new TypeFilter<>(CtInvocation.class))) {
+            if (!isCompatibleLogbackInvocation(invocation, logbackLoggerVariables)) {
+                continue;
+            }
+
+            CtStatement statement = invocation.getParent(CtStatement.class);
+            if (statement == null) {
+                continue;
+            }
+
+            String target = invocation.getTarget() == null ? null : invocation.getTarget().toString();
+            if (target == null) {
+                continue;
+            }
+
+            String snippet = switch (invocation.getExecutable().getSimpleName()) {
+                case "setLevel" -> reflectiveCall(target, "setLevel", LOGBACK_LEVEL, invocation.getArguments().get(0).toString());
+                case "addAppender" -> reflectiveCall(target, "addAppender", LOGBACK_APPENDER, invocation.getArguments().get(0).toString());
+                default -> null;
+            };
+
+            if (snippet != null) {
+                statement.replace(factory.Code().createCodeSnippetStatement(snippet));
+            }
+        }
+
+        launcher.prettyprint();
+    }
+
+    private static boolean isCompatibleLogbackInvocation(CtInvocation<?> invocation, Set<String> logbackLoggerVariables) {
+        if (!Set.of("setLevel", "addAppender").contains(invocation.getExecutable().getSimpleName())) {
+            return false;
+        }
+        CtExpression<?> target = invocation.getTarget();
+        if (!(target instanceof CtVariableRead<?> variableRead)) {
+            return false;
+        }
+        return logbackLoggerVariables.contains(variableRead.getVariable().getSimpleName());
+    }
+
+    private static boolean isLogbackLogger(CtTypeReference<?> typeReference) {
+        return typeReference != null && LOGBACK_LOGGER.equals(typeReference.getQualifiedName());
+    }
+
+    private static String reflectiveCall(String target, String methodName, String parameterType, String argument) {
+        return "try { "
+                + "java.lang.reflect.Method method = " + target + ".getClass().getMethod(\"" + methodName + "\", " + parameterType + ".class); "
+                + "method.invoke(" + target + ", " + argument + "); "
+                + "} catch (java.lang.ReflectiveOperationException e) { "
+                + "throw new java.lang.IllegalStateException(e); }";
+    }
+
+    private static String childText(Element parent, String tagName) {
+        Node node = childNode(parent, tagName);
+        return node == null ? null : node.getTextContent();
+    }
+
+    private static Node childNode(Element parent, String tagName) {
+        NodeList children = parent.getElementsByTagName(tagName);
+        if (children.getLength() == 0) {
+            return null;
+        }
+        return children.item(0);
+    }
+
+    private static void appendChildElement(Document document, Element parent, String name, String value) {
+        Element child = document.createElement(name);
+        child.setTextContent(value);
+        parent.appendChild(child);
+    }
+}
*** End Patch

